// src/components/Sidebar.jsx
import React from 'react';
import {
  Home,
  CalendarDays,
  BookOpen,
  Users,
  UserRound,
  Mail,
  Settings,
  HelpCircle,
} from 'lucide-react';
import { useAuth } from '../context/AuthContext';

export default function Sidebar({ active, onMenuClick }) {
  const { user } = useAuth();
  // assume your user object has a `nome` field; fallback to `usuario` if needed
  const fullName = user?.nome || user?.usuario || '';
  const firstName = fullName.split(' ')[0];

  return (
    <aside className="flex flex-col justify-between w-64 h-screen bg-white fixed top-0 left-0 z-30 print:hidden">
      {/* Usuário logado */}
      <div className="flex items-center gap-3 px-6 py-4 border-b">
        <UserRound size={32} className="text-gray-600" />
        <span className="text-base font-semibold text-gray-800">
          {firstName}
        </span>
      </div>

      {/* Menu principal */}
      <nav className="flex flex-col gap-2 mt-4 px-6">
        <MenuItem
          icon={<Home size={24} />}
          label="Dashboard"
          active={active === 'dashboard'}
          onClick={() => onMenuClick('dashboard')}
        />
        <MenuItem
          icon={<CalendarDays size={24} />}
          label="Agendar Paciente"
          active={active === 'agendar'}
          onClick={() => onMenuClick('agendar')}
        />
        <MenuItem
          icon={<Users size={24} />}
          label="Pacientes"
          active={active === 'pacientes'}
          onClick={() => onMenuClick('pacientes')}
        />
        <MenuItem
          icon={<UserRound size={24} />}
          label="Alunos"
          active={active === 'alunos'}
          onClick={() => onMenuClick('alunos')}
        />
        <MenuItem
          icon={<BookOpen size={24} />}
          label="Disciplinas"
          active={active === 'disciplinas'}
          onClick={() => onMenuClick('disciplinas')}
        />
        <MenuItem
          icon={<Mail size={24} />}
          label="Períodos"
          active={active === 'periodos'}
          onClick={() => onMenuClick('periodos')}
        />
      </nav>

      {/* Configurações e ajuda */}
      <div className="flex flex-col gap-2 mb-10 px-6">
        <MenuItem
          icon={<Settings size={24} />}
          label="Configurações"
          active={active === 'configuracoes'}
          onClick={() => onMenuClick('configuracoes')}
        />
        <MenuItem
          icon={<HelpCircle size={24} />}
          label="Ajuda"
          active={active === 'ajuda'}
          onClick={() => onMenuClick('ajuda')}
        />
      </div>
    </aside>
  );
}

function MenuItem({ icon, label, active, onClick }) {
  return (
    <button
      onClick={onClick}
      className={`flex items-center gap-3 py-3 px-4 rounded-full text-base transition-all ${
        active
          ? 'bg-[#D9E0FF] text-[#23263A]'
          : 'text-[#23263A] hover:bg-gray-100'
      }`}
      style={{
        boxShadow: active
          ? '0px 2px 8px 0px rgba(100, 116, 139, 0.08)'
          : undefined,
      }}
    >
      {icon}
      {label}
    </button>
  );
}
